
UPDATE public.memory_items SET summary = 'Armando ha imparato che in un''espressione matematica, le moltiplicazioni e le divisioni vanno eseguite prima delle addizioni e delle sottrazioni.' WHERE id = 'a3a5e2d7-23d1-478c-a5c6-b59a07ded4a3';

UPDATE public.memory_items SET summary = 'Armando ha compreso che le operazioni all''interno delle parentesi tonde devono essere risolte per prime, come una priorità assoluta nell''espressione.' WHERE id = '60170446-e374-41b2-b2b8-247c5704f39c';

UPDATE public.memory_items SET summary = 'Armando ha imparato che quando si incontrano moltiplicazioni e divisioni nella stessa espressione (senza parentesi), si eseguono nell''ordine in cui compaiono, da sinistra a destra.' WHERE id = '6e5907a8-3a73-452b-bc78-166078d915b7';

UPDATE public.memory_items SET summary = 'Armando ha capito che anche addizioni e sottrazioni hanno la stessa priorità e si eseguono nell''ordine in cui si presentano nell''espressione, da sinistra a destra.' WHERE id = '1d52c013-625d-4030-be4d-3a1c4618bddb';

UPDATE public.memory_items SET summary = 'La frazione è stata spiegata a Mariaclara usando esempi semplici come una pizza o una tavoletta di cioccolata, per rappresentare parti di un intero. Mariaclara ha iniziato a capire il concetto base.' WHERE id = 'f1a9463b-eb96-4810-a0bb-5932bf5af2af';

UPDATE public.memory_items SET summary = 'Mariaclara ha imparato a identificare e utilizzare il numeratore (la parte sopra) e il denominatore (la parte sotto) in semplici frazioni rappresentate da pezzi di cioccolata. Ha anche scritto correttamente le frazioni numericamente.' WHERE id = '40aa15db-2220-412d-bb79-68cd03244080';

UPDATE public.memory_items SET summary = 'Attraverso l''uso di esempi visivi come la pizza e la cioccolata, Mariaclara ha compreso come le frazioni rappresentano parti concrete di un intero. Ha dimostrato di associare correttamente le azioni (mangiare pezzi) alla rappresentazione frazionaria.' WHERE id = 'f8deab0e-a2ea-4761-98a1-1bb657ca81f6';
